<script setup lang="ts">import { useI18n } from 'vue-i18n';import type { TestResult } from '@/types/apiTest';defineProps<{result:TestResult|null;error:string}>();defineEmits<{copy:[];clear:[]}>();const{t}=useI18n()</script>
<template><section class="test-results"><header><h2>{{t('apiTest.results')}}</h2><div class="button-row"><button type="button" :disabled="!result" @click="$emit('copy')">{{t('apiTest.copy')}}</button><button type="button" :disabled="!result&&!error" @click="$emit('clear')">{{t('apiTest.clear')}}</button></div></header><p v-if="error" class="error-text">{{error}}</p><template v-if="result"><p>{{t('apiTest.elapsed')}}: {{result.elapsedMs}} ms <span v-if="result.interrupted">· {{t('apiTest.interrupted')}}</span></p><div class="output-grid"><div><h3>{{t('apiTest.reasoning')}}</h3><pre>{{result.reasoning||t('apiTest.empty')}}</pre></div><div><h3>{{t('apiTest.content')}}</h3><pre>{{result.content||t('apiTest.empty')}}</pre></div></div><h3>{{t('apiTest.complete')}}</h3><pre>{{JSON.stringify(result.raw,null,2)}}</pre><p>{{t('apiTest.usage')}}: {{result.usage===null?t('apiTest.unknown'):JSON.stringify(result.usage)}}</p></template></section></template>
